CacheAccess<String, String> jcs = JCS.getInstance( "myregion" );

. . .

// ElementAttributes is an immutable record
IElementAttributes defaultAttributes = jcs.getDefaultElementAttributes();

// set some special values
IElementAttributes attributes = new ElementAttributes(
    defaultAttributes.isSpool(), 
    defaultAttributes.isLateral(), 
    defaultAttributes.isRemote(), 
    /* isEternal   */ false, 
    /* maxLife     */ Duration.ofSeconds(1800), 
    /* maxIdleTime */ Duration.ofSeconds(900));

jcs.put( "key", "data", attributes );


CacheAccess<String, String> jcs = JCS.getInstance( "myregion" );

. . .

// ElementAttributes is an immutable record
IElementAttributes defaulAttributes = jcs.getDefaultElementAttributes();

// set some special values
IElementAttributes attributes = new ElementAttributes(
    defaultAttributes.isSpool(), 
    defaultAttributes.isLateral(), 
    defaultAttributes.isRemote(), 
    /* isEternal   */ false, 
    /* maxLife     */ Duration.ofSeconds(1800), 
    /* maxIdleTime */ Duration.ofSeconds(900));

jcs.setDefaultElementAttributes( attributes );
